use chrono::{DateTime, Utc};
use uuid::Uuid;

use super::todo_title::TodoTitle;
use super::user::UserId;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WaitingForId(Uuid);

impl Default for WaitingForId {
    fn default() -> Self {
        Self::new()
    }
}

impl WaitingForId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }

    pub fn from_uuid(uuid: Uuid) -> Self {
        Self(uuid)
    }

    pub fn as_uuid(&self) -> &Uuid {
        &self.0
    }
}

/// The person or entity the user is waiting on. Non-empty, max 100 chars, trimmed.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WaitingOnPerson(String);

const WAITING_ON_MAX_LENGTH: usize = 100;

#[derive(Debug, Clone, thiserror::Error)]
pub enum WaitingOnPersonError {
    #[error("Waiting-on person cannot be empty")]
    Empty,
    #[error("Waiting-on person too long (max {max}, got {actual})")]
    TooLong { max: usize, actual: usize },
}

impl WaitingOnPerson {
    pub fn parse(input: String) -> Result<Self, WaitingOnPersonError> {
        let trimmed = input.trim().to_string();
        if trimmed.is_empty() {
            return Err(WaitingOnPersonError::Empty);
        }
        if trimmed.len() > WAITING_ON_MAX_LENGTH {
            return Err(WaitingOnPersonError::TooLong {
                max: WAITING_ON_MAX_LENGTH,
                actual: trimmed.len(),
            });
        }
        Ok(Self(trimmed))
    }

    pub fn as_str(&self) -> &str {
        &self.0
    }
}

/// An item the user is waiting on from someone else.
///
/// State machine:
///   Active --complete()--> Completed (received/resolved)
///
/// Completed items are removed from the active Waiting For list.
#[derive(Debug, Clone)]
pub enum WaitingForItem {
    Active {
        id: WaitingForId,
        user_id: UserId,
        title: TodoTitle,
        waiting_on: WaitingOnPerson,
        created_at: DateTime<Utc>,
    },
    Completed {
        id: WaitingForId,
        user_id: UserId,
        title: TodoTitle,
        waiting_on: WaitingOnPerson,
        created_at: DateTime<Utc>,
        completed_at: DateTime<Utc>,
    },
}

impl WaitingForItem {
    pub fn new(user_id: UserId, title: TodoTitle, waiting_on: WaitingOnPerson) -> Self {
        Self::Active {
            id: WaitingForId::new(),
            user_id,
            title,
            waiting_on,
            created_at: Utc::now(),
        }
    }

    pub fn from_parts(
        id: WaitingForId,
        user_id: UserId,
        title: TodoTitle,
        waiting_on: WaitingOnPerson,
        created_at: DateTime<Utc>,
        completed_at: Option<DateTime<Utc>>,
    ) -> Self {
        match completed_at {
            Some(completed_at) => Self::Completed {
                id,
                user_id,
                title,
                waiting_on,
                created_at,
                completed_at,
            },
            None => Self::Active {
                id,
                user_id,
                title,
                waiting_on,
                created_at,
            },
        }
    }

    pub fn id(&self) -> &WaitingForId {
        match self {
            Self::Active { id, .. } | Self::Completed { id, .. } => id,
        }
    }

    pub fn user_id(&self) -> &UserId {
        match self {
            Self::Active { user_id, .. } | Self::Completed { user_id, .. } => user_id,
        }
    }

    pub fn title(&self) -> &TodoTitle {
        match self {
            Self::Active { title, .. } | Self::Completed { title, .. } => title,
        }
    }

    pub fn waiting_on(&self) -> &WaitingOnPerson {
        match self {
            Self::Active { waiting_on, .. } | Self::Completed { waiting_on, .. } => waiting_on,
        }
    }

    pub fn created_at(&self) -> &DateTime<Utc> {
        match self {
            Self::Active { created_at, .. } | Self::Completed { created_at, .. } => created_at,
        }
    }

    pub fn is_active(&self) -> bool {
        matches!(self, Self::Active { .. })
    }

    pub fn is_completed(&self) -> bool {
        matches!(self, Self::Completed { .. })
    }

    /// Transitions an Active waiting-for item to Completed (received/resolved).
    /// If already completed, returns self unchanged.
    pub fn complete(self) -> Self {
        match self {
            Self::Active {
                id,
                user_id,
                title,
                waiting_on,
                created_at,
            } => Self::Completed {
                id,
                user_id,
                title,
                waiting_on,
                created_at,
                completed_at: Utc::now(),
            },
            completed @ Self::Completed { .. } => completed,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn waiting_for_id_is_unique() {
        let id1 = WaitingForId::new();
        let id2 = WaitingForId::new();
        assert_ne!(id1, id2);
    }

    #[test]
    fn waiting_for_id_from_uuid_roundtrips() {
        let uuid = Uuid::new_v4();
        let id = WaitingForId::from_uuid(uuid);
        assert_eq!(id.as_uuid(), &uuid);
    }

    #[test]
    fn valid_waiting_on_person_is_accepted() {
        let person = WaitingOnPerson::parse("Alice".to_string()).unwrap();
        assert_eq!(person.as_str(), "Alice");
    }

    #[test]
    fn waiting_on_person_is_trimmed() {
        let person = WaitingOnPerson::parse("  Bob  ".to_string()).unwrap();
        assert_eq!(person.as_str(), "Bob");
    }

    #[test]
    fn empty_waiting_on_person_is_rejected() {
        let result = WaitingOnPerson::parse("".to_string());
        assert!(matches!(result, Err(WaitingOnPersonError::Empty)));
    }

    #[test]
    fn whitespace_only_waiting_on_person_is_rejected() {
        let result = WaitingOnPerson::parse("   ".to_string());
        assert!(matches!(result, Err(WaitingOnPersonError::Empty)));
    }

    #[test]
    fn waiting_on_person_at_max_length_is_accepted() {
        let name = "a".repeat(100);
        let person = WaitingOnPerson::parse(name.clone()).unwrap();
        assert_eq!(person.as_str(), &name);
    }

    #[test]
    fn waiting_on_person_exceeding_max_length_is_rejected() {
        let name = "a".repeat(101);
        let result = WaitingOnPerson::parse(name);
        assert!(matches!(
            result,
            Err(WaitingOnPersonError::TooLong { max: 100, .. })
        ));
    }

    #[test]
    fn new_waiting_for_item_is_active() {
        let user_id = UserId::new();
        let title = TodoTitle::parse("Fix server bug".to_string()).unwrap();
        let waiting_on = WaitingOnPerson::parse("DevOps team".to_string()).unwrap();
        let item = WaitingForItem::new(user_id, title, waiting_on);

        assert!(item.is_active());
        assert!(!item.is_completed());
        assert_eq!(item.title().as_str(), "Fix server bug");
        assert_eq!(item.waiting_on().as_str(), "DevOps team");
    }

    #[test]
    fn new_waiting_for_item_has_user() {
        let user_id = UserId::new();
        let title = TodoTitle::parse("Get approval".to_string()).unwrap();
        let waiting_on = WaitingOnPerson::parse("Manager".to_string()).unwrap();
        let item = WaitingForItem::new(user_id.clone(), title, waiting_on);

        assert_eq!(item.user_id(), &user_id);
    }

    #[test]
    fn complete_transitions_active_to_completed() {
        let item = WaitingForItem::new(
            UserId::new(),
            TodoTitle::parse("Receive package".to_string()).unwrap(),
            WaitingOnPerson::parse("Amazon".to_string()).unwrap(),
        );

        let completed = item.complete();
        assert!(completed.is_completed());
        assert!(!completed.is_active());
    }

    #[test]
    fn complete_preserves_id_and_fields() {
        let user_id = UserId::new();
        let title = TodoTitle::parse("Get quote".to_string()).unwrap();
        let waiting_on = WaitingOnPerson::parse("Contractor".to_string()).unwrap();
        let item = WaitingForItem::new(user_id.clone(), title, waiting_on);
        let id = item.id().clone();

        let completed = item.complete();
        assert_eq!(completed.id(), &id);
        assert_eq!(completed.user_id(), &user_id);
        assert_eq!(completed.title().as_str(), "Get quote");
        assert_eq!(completed.waiting_on().as_str(), "Contractor");
    }

    #[test]
    fn complete_is_noop_on_completed_item() {
        let item = WaitingForItem::new(
            UserId::new(),
            TodoTitle::parse("Already received".to_string()).unwrap(),
            WaitingOnPerson::parse("Vendor".to_string()).unwrap(),
        );
        let completed = item.complete();
        let still_completed = completed.complete();
        assert!(still_completed.is_completed());
    }

    #[test]
    fn from_parts_creates_active_when_no_completed_at() {
        let id = WaitingForId::new();
        let user_id = UserId::new();
        let title = TodoTitle::parse("Test".to_string()).unwrap();
        let waiting_on = WaitingOnPerson::parse("Someone".to_string()).unwrap();
        let now = Utc::now();

        let item =
            WaitingForItem::from_parts(id.clone(), user_id.clone(), title, waiting_on, now, None);

        assert!(item.is_active());
        assert_eq!(item.id(), &id);
        assert_eq!(item.user_id(), &user_id);
        assert_eq!(item.created_at(), &now);
    }

    #[test]
    fn from_parts_creates_completed_when_completed_at_present() {
        let id = WaitingForId::new();
        let user_id = UserId::new();
        let title = TodoTitle::parse("Done".to_string()).unwrap();
        let waiting_on = WaitingOnPerson::parse("Other".to_string()).unwrap();
        let created = Utc::now();
        let completed = Utc::now();

        let item = WaitingForItem::from_parts(
            id.clone(),
            user_id,
            title,
            waiting_on,
            created,
            Some(completed),
        );

        assert!(item.is_completed());
        assert_eq!(item.id(), &id);
    }
}

